// Get Gemini's response text
const geminiResponse = $input.first().json.content.parts[0].text;

// Clean it up — remove markdown backticks if any
const cleaned = geminiResponse
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// Parse it into proper JSON
let memo = JSON.parse(cleaned);

// Add extra fields
memo.account_id = "account_001";
memo.version = "v1";
memo.source = "demo_call";
memo.generated_at = new Date().toISOString();

// Convert to binary so Write File node can save it
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(JSON.stringify(memo, null, 2)),
  'account_memo.json',
  'application/json'
);

return {
  json: memo,
  binary: {
    data: binaryData
  }
};

// Step 1: Get Gemini response
const geminiResponse =
  $input.first().json.content?.parts?.[0]?.text ||
  $input.first().json.text ||
  $input.first().json.content ||
  "";

// Step 2: Remove markdown
let cleaned = geminiResponse
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// Step 3: Extract JSON only
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');

if (start === -1 || end === -1) {
  throw new Error("❌ No valid JSON found:\n" + cleaned);
}

cleaned = cleaned.substring(start, end + 1);

// ❌ DO NOT TOUCH NEWLINES HERE

// Step 4: Parse directly
let agentSpec;
try {
  agentSpec = JSON.parse(cleaned);
} catch (err) {
  throw new Error("❌ JSON Parse Failed:\n" + cleaned);
}

// Step 5: Add metadata
agentSpec.account_id = "account_001";
agentSpec.version = "v1";
agentSpec.generated_at = new Date().toISOString();

// Step 6: Return JSON
return [{ json: agentSpec }];

